  ('public-health-specialist-moex-00924', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '根據衛生福利部食品藥物管理署的統計資料，下列那種病因是近年來我國食品中毒病因案件 數之第一名?', '["金黃色葡萄球菌", "李斯特菌", "諾羅病毒", "天然毒素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00925', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '我國「飲用水水質標準」的細菌性標準除了總菌落數之外，還檢測水中的何種細菌？', '["葡萄球菌", "大腸桿菌群", "腸炎弧菌", "傷寒桿菌"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00926', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '「食品良好衛生規範準則」（GHP）係依「食品安全衛生管理法」第8條第4項規定訂定，該準 則從四大面向要求各類食品相關業者均須符合相關規定。下列關於GHP的規範，何者正確？', '["食品業者之從業人員、作業場所、設施衛生管理及其品保制度，均應符合食品之良好衛生 規範準則", "GHP規範的食品業者不包括塑膠類食品器具、食品容器或包裝製造業", "GHP規範的食品業者場區及環境範圍不包括員工宿舍", "冷凍食品之品溫應在攝氏負10度以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00927', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '關於病媒蚊的描述，下列何者正確？', '["白線斑蚊為近年臺灣登革熱流行最主要的病媒蚊", "埃及斑蚊多孳生於室內或居家附近之積水容器", "熱帶家蚊為臺灣日本腦炎最主要的病媒蚊", "三斑家蚊為傳播絲蟲病最主要的病媒蚊"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00928', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '關於茲卡病毒感染症（Zikavirusinfection），下列敘述何者錯誤？', '["在臺灣，可傳播茲卡病毒的病媒蚊包括埃及斑蚊及白線斑蚊", "臺灣迄今尚未出現境內、境外移入病例", "茲卡病毒感染者可透過性行為把病毒傳給其性伴侶；也可經由母嬰垂直傳染", "婦女於懷孕期間感染茲卡病毒，可能產下小頭畸形新生兒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00929', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '關於空氣污染物細懸浮微粒（PM2.5），下列敘述何者錯誤？', '["PM2.5表面積很大，可吸附許多毒性物質，例如有毒氣體、重金屬、戴奧辛類、致癌性多 環芳香烴等", "PM2.5最可能在肺部支氣管沉積，靠氣管內的吞噬細胞捕獲、進入體內代謝、吸收、消除， 在上述過程中危害人體健康", "氣狀空氣污染物，可能因陽光照射下產生光化學反應，生成衍生性PM2.5", "PM2.5國家空氣品質標準：24小時值為35μg/m3（微克/立方公尺）；年平均值為15μg/m3 （微克/立方公尺）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00930', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '下列那種物質是國際癌症研究所（IARC）分類表中的第一類（Group1）致癌物質？', '["黃麴毒素", "鉛", "甲苯", "黃樟素"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00931', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '氰化物為劇毒性物質，若在一般情況使用或廢液處理過程中，不當接觸酸液，可能產生氰化 氫氣體，立即危害人體健康或生物生命者。氰化物屬於第幾類毒性化學物質？', '["1", "2", "3", "4"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00932', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '關於環境中重金屬污染引起之疾病，下列敘述何者錯誤？', '["含汞廢水未經處理排放，無機汞被水中生物轉化成甲基汞，甲基汞在食物中蓄積，人類長 期食用後發生水俁病（Minamatadisease）", "痛痛病（Itai-Itaidisease）是人類長期飲用被鎘污染飲用水與吃受鎘污染稻米所致", "鉛不是人體功能必須之金屬，小孩過量暴露會引起神經行為損傷", "近年來，臺灣環境中鉛污染來源主要是汽車使用含鉛汽油，由汽車廢氣污染環境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00933', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '我國的「毒性化學物質管理法」於108年修正為「毒性及關注化學物質管理法」，其中關注化 學物質又於 110 年 8 月 20 日公告新增列管二種化學物質為具有危害性的關注化學物質，其 中一種化學品曾於109年8月間於黎巴嫩首都貝魯特港口大量貯存引起震驚全球之大爆炸事 件。請指出是那種化學物質？', '["一氧化二氮（N O）", "硝酸銨（NH NO ）", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00934', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '4 3', '["氰化氫（HCN）", "氟化氫（HF）", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00935', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '我國「再生能源發展條例」所定義的再生能源，不包括下列何者？', '["太陽能", "生質能", "天然氣", "廢棄物直接利用或經處理所產生之能源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00936', 'public-health-specialist', 'public-health-specialist-moex-110-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '關於全球電子產品廢棄物（ElectronicProductsWastes）已受到國際特別關注，下列敘述何者 錯誤？', '["國際上訂有日內瓦公約（GenevaConvention），約定電子產品廢棄物無聲交易為違法，有害 廢棄物禁止由OECD國家境外運送到非OECD國家", "近年科技產品推陳出新速度快，壽命短，電子產品廢棄物數量大幅增長，處理方式卻多是 拆解、焚燒、回收、再利用，而且許多都在非OECD國家", "電子產品廢棄物中含有砷（As）、鎘（Cd）、鉻（Cr）、鉛（Pb）、汞（Hg）、聚氯乙烯（PVC）、 溴、鄰苯二甲酸……等毒性物質，近年才逐漸減少", "電子產品廢棄如果採焚化處理回收，低溫燃燒會產生戴奧辛及呋喃"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "4b5f66fcdd3f", "answer_pdf_sha1": "864fd3ab65dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
